106	- (void)viewDidLoad {
107	    [super viewDidLoad];
108	    // Do any additional setup after loading the view.
109	    if (![CTMediator isSDK2ndCar]) {
110	        self.keyViewModel = [XPBLEKeyManager.instance viewModelWithVin:self.carInfo.vin];
111	    } else {
112	        self.appleWatchKeyCard = [self findAppleWatchCard];
113	        self.nfcWatchKeyCard = [self findCardWithType:XPBLEKeyCardType_NFCWatchKey];
114	        [self updateSettingData];
115	    }
116	
117	    @weakify(self)
118	    [self.rac_deallocDisposable addDisposable:[RACObserve(self.keyViewModel, myCardList).deliverOnMainThread subscribeNext:^(id  _Nullable x) {
119	        @strongify(self)
120	        self.cardList = x;
121	        if(self.cardList.count > 0){
122	            self.bleKeyCard = [self findBLECard];
123	            self.nfcWatchKeyCard = [self findCardWithType:XPBLEKeyCardType_NFCWatchKey];
124	            self.appleWatchKeyCard = [self findAppleWatchCard];
125	        }else{
126	            self.bleKeyCard = nil;
127	            self.nfcWatchKeyCard = nil;
128	            self.appleWatchKeyCard = nil;
129	        }
130	        [self updateSettingData];
131	    }]];
132	    
133	    [self.rac_deallocDisposable addDisposable:[[NSNotificationCenter.defaultCenter rac_addObserverForName:XPVehicleNotification.DigitalKeyStateChanged object:nil].deliverOnMainThread subscribeNext:^(NSNotification * _Nullable x) {
134	        @strongify(self)
135	        self.appleWatchKeyCard = [self findAppleWatchCard];
136	        self.nfcWatchKeyCard = [self findCardWithType:XPBLEKeyCardType_NFCWatchKey];
137	        [self updateSettingData];
138	    }]];
139	
140	
141	    [self.rac_deallocDisposable addDisposable:[[RACObserve(XPMultiBleManager.sharedManager, pollingRunMode) skip:1].deliverOnMainThread subscribeNext:^(id  _Nullable x) {
142	        @strongify(self)
143	        [self updateSettingData];
144	    }]];
145	    
146	    [self.rac_deallocDisposable addDisposable:[[NSNotificationCenter.defaultCenter rac_addObserverForName:XPDeletingBleKeyNotification object:nil].deliverOnMainThread subscribeNext:^(NSNotification * _Nullable x) {
147	        @strongify(self);
148	        [self updateSettingData];
149	    }]];
150	    
151	    [self.rac_deallocDisposable addDisposable:[[NSNotificationCenter.defaultCenter rac_addObserverForName:XPCreatingBleKeyNotification object:nil].deliverOnMainThread subscribeNext:^(NSNotification * _Nullable x) {
152	        @strongify(self);
153	        [self updateSettingData];
154	    }]];
155	
156	    [self updateSettingData];
157	    [self setupNav];
158	}
