171	- (BOOL)isBLECardValid{
172	    if ([CTMediator isMona]) {
173	        if ([XPVehicleSDK.shared.vehicleManager.currentVehicle.digitalKeyManager existValidBlePrivateKey]) {
174	            return YES;
175	        }
176	        NSString *keyWithVin = [NSString stringWithFormat:@"com.xiaopeng.XPCreateMonaKeyViewController.waitNearCar.%@.%lld", XPVehicleSDK.shared.vehicleManager.currentVehicle.vehiclePreference.vin,[CTMediator uid]];
177	        if ([MMKV.defaultMMKV getBoolForKey:keyWithVin] && [XPVehicleSDK existToBeActivateBLEKey]) {
178	            return YES;
179	        }
180	        return NO;
181	    }
182	    return [CTMediator isSDK2ndCar] ? [XPVehicleSDK.shared.vehicleManager.currentVehicle.digitalKeyManager existValidBlePrivateKey] : [self cardIsValid:self.bleKeyCard];
183	}
