228	- (void)updateSettingData{
229	    NSMutableArray *sectionItems = [NSMutableArray new];
230	    XPKeySettingSectionItem *bleSection = [XPKeySettingSectionItem new];
231	    XPKeySettingCellItem *bleKeyItem = [[XPKeySettingCellItem alloc] initWithType:XPKeySettingCellTypeBleKey];
232	    bleKeyItem.title = @"手机钥匙";
233	    XPKeySettingCellItem *bleLoginItem = [[XPKeySettingCellItem alloc] initWithType:XPKeySettingCellTypeBleLoginScreen];
234	    bleLoginItem.switchSelected = self.bleLoginScreen;
235	    bleLoginItem.paddingTop = 8.0*AdaptiveRatio;
236	    
237	    NSMutableArray *bleCells = [NSMutableArray new];
238	    [bleCells addObject:bleKeyItem];
239	    if(self.isBLECardValid){
240	        bleKeyItem.isCardValid = YES;
241	        
242	        if (![CTMediator isMona]) {
243	            [bleCells addObject:bleLoginItem];
244	        }
245	    }
246	    XPKeySettingCellItem *pollingSettingItem = [[XPKeySettingCellItem alloc] initWithType:XPKeySettingCellTypeBLEPollingEntrance];
247	    if ([CTMediator isMona]) {
248	        pollingSettingItem.showInfoButton = NO;
249	    }
250	    // Mona 车型自动开启大屏登录和自动解闭锁
251	    if(self.isBLECardValid && !self.carInfo.isE28 && !self.carInfo.carFunction.BIG_CUSTOMER){
252	        [bleCells addObject:pollingSettingItem];
253	    }
254	    bleSection.cellItems = bleCells;
255	    [sectionItems addObject:bleSection];
256	    
257	    XPKeySettingSectionItem *deviceKeySection = [XPKeySettingSectionItem new];
258	    deviceKeySection.headerTitle = @"设备钥匙";
259	    NSMutableArray *deviceKeyCells = [NSMutableArray new];
260	    
261	    if(self.appleWatchKeyCard){
262	        XPKeySettingCellItem *bleWatchKeyItem = [[XPKeySettingCellItem alloc] initWithType:XPKeySettingCellTypeAppleWatchKey];
263	        bleWatchKeyItem.isCardValid = YES;
264	        [deviceKeyCells addObject:bleWatchKeyItem];
265	    }
266	    BOOL nfcOld = ![CTMediator isSDK2ndCar] && (self.carInfo.isE28 && self.carInfo.isSupportNFCKey == XPNFCKeySupportState_Support && self.carInfo.isMyOwnerCar);
267	    BOOL nfcNew = [CTMediator isSDK2ndCar] && XPVehicleSDK.shared.vehicleManager.currentVehicle.vehiclePreference.function.NFC_WATCH_KEY && XPVehicleSDK.shared.vehicleManager.currentVehicle.vehiclePreference.extInfo.nfcKeyFunState == XPNFCKeyFunctionStateSupported && XPVehicleSDK.shared.vehicleManager.currentVehicle.vehiclePreference.hasOwnerPermissions;
268	    if(nfcOld || nfcNew){
269	        XPKeySettingCellItem *nfcWatchKeyItem = [[XPKeySettingCellItem alloc] initWithType:XPKeySettingCellTypeNfcWatchKey];
270	        if([self cardIsValid:self.nfcWatchKeyCard]){
271	            nfcWatchKeyItem.isCardValid = YES;
272	        }
273	        if(deviceKeyCells.count > 0){
274	            nfcWatchKeyItem.paddingTop = 12*AdaptiveRatio;
275	        }
276	        [deviceKeyCells addObject:nfcWatchKeyItem];
277	        
278	        XPKeySettingCellItem *nfcPhoneKeyItem = [[XPKeySettingCellItem alloc] initWithType:XPKeySettingCellTypeNfcPhoneKey];
279	        nfcPhoneKeyItem.isCardUnavailable = YES;
280	        nfcPhoneKeyItem.paddingTop = 12*AdaptiveRatio;
281	        [deviceKeyCells addObject:nfcPhoneKeyItem];
282	    }
283	    
284	    deviceKeySection.cellItems = deviceKeyCells;
285	    if(deviceKeySection.cellItems.count > 0){
286	        [sectionItems addObject:deviceKeySection];
287	        bleSection.footerSeparator = YES;
288	        if(bleSection.cellItems.count == 1){
289	            bleKeyItem.paddingBottom = -25*AdaptiveRatio;
290	        }
291	    }
292	    
293	    self.sectionItems = sectionItems;
294	    [self.tableView reloadData];
295	}
