297	- (XPKeySettingCellItem *)cellItemWithType:(XPKeySettingCellType)type{
298	    for(XPKeySettingSectionItem *sectionItem in self.sectionItems){
299	        for(XPKeySettingCellItem *cellItem in sectionItem.cellItems){
300	            if(cellItem.type == type){
301	                return cellItem;
302	            }
303	        }
304	    }
305	    return nil;
306	}
