308	- (XPBLEKeyCard *)findCardWithType:(XPBLEKeyCardType)type {
309	    if ([CTMediator isSDK2ndCar]) {
310	        return [XPBLEKeyCard yy_modelWithDictionary:[XPVehicleSDK.shared.vehicleManager.currentVehicle.digitalKeyManager digitalKeyWithKeyCardType:(XPKeyCardType)type].bleKeyCard.toDict];
311	    }
312	    for (XPBLEKeyCard *aCard in self.cardList) {
313	        if(aCard.cardType == type) {
314	            return aCard;
315	        }
316	    }
317	    return nil;
318	}
