320	- (XPBLEKeyCard *)findAppleWatchCard{
321	    XPBLEKeyCard *card = [CTMediator isSDK2ndCar]?[XPBLEKeyCard yy_modelWithDictionary: [[XPVehicleSDK.shared.vehicleManager.currentVehicle.digitalKeyManager digitalKeyWithKeyCardType:XPKeyCardTypeAPPLE_WATCH].bleKeyCard toDict]]:[self findCardWithType:XPBLEKeyCardType_WatchCertKey];
322	    if(card.status == XPBLEKeyCardStatusPreCreated && !self.carInfo.isMyOwnerCar){
323	        return nil;
324	    }
325	    return card;
326	}
