328	- (XPBLEKeyCard *)findBLECard {
329	    XPBLEKeyCard *bleMonaCard = [self findCardWithType:XPBLEKeyCardType_BLEMonaKey];
330	    if (bleMonaCard) {
331	        return bleMonaCard;
332	    }
333	
334	    XPBLEKeyCard *bleCard = [self findCardWithType:XPBLEKeyCardType_BLEKey];
335	    XPBLEKeyCard *bleCertKeyCard = [self findCardWithType:XPBLEKeyCardType_BLECertKey];
336	    if(!bleCertKeyCard) {
337	        bleCertKeyCard = [self findCardWithType:XPBLEKeyCardType_BLESelfKey];
338	    }
339	    
340	    XPBLEKeyCard *mergeBleCard = nil;
341	    if(bleCard && bleCertKeyCard) {
342	        DLogTagInfo(kBLEKeyTag, @"服务器的安全和证书钥匙都存在, 安全钥匙：%@, 证书钥匙：%@", bleCard, bleCertKeyCard);
343	        if(bleCard.isValid){
344	            mergeBleCard = bleCard;
345	        }else{
346	            mergeBleCard = bleCertKeyCard;
347	        }
348	    } else if(bleCard) {
349	        DLogTagInfo(kBLEKeyTag, @"只存在安全钥匙：%@", bleCard);
350	        mergeBleCard = bleCard;
351	    } else if(bleCertKeyCard) {
352	        DLogTagInfo(kBLEKeyTag, @"只存在证书钥匙：%@", bleCertKeyCard);
353	        mergeBleCard = bleCertKeyCard;
354	    } else {
355	        DLogTagInfo(kBLEKeyTag, @"安全和证书钥匙都不存在");
356	    }
357	
358	    return mergeBleCard;
359	}
360	
361	- (BOOL)cardIsValid:(XPBLEKeyCard *)card{
362	    if(!card) return NO;
363	    
364	    //安全钥匙需要判断设备，证书钥匙没那么多状态，安全钥匙（一砂）才需要检测各种状态
365	    if(card.cardType == XPBLEKeyCardType_BLEKey || card.cardType == XPBLEKeyCardType_BLEMonaKey) return card.isValid;
366	    
367	    return card.status == XPBLEKeyCardStatusNormal;
368	}
