407	- (void)deleteKeyButtonDidClickWithCard:(XPBLEKeyCard *)card{
408	    [XPStatisticsMgr sendEvent:XP_DELETE_BLE_KEY module:XP_DIGITAL_KEY_MANAGER_MODULE];
409	    
410	    MyCarInfo *carInfo = self.carInfo;
411	    if(carInfo.isE28) {
412	        DLogTagInfo(kBLEKeyTag, @"是e28，跳到原来钥匙删除流程");
413	        BOOL existSafeOld = ![CTMediator isSDK2ndCar] && XPBLEKeyManager.instance.defaultCard;
414	        BOOL existSafeNew = [CTMediator isSDK2ndCar] && [XPVehicleSDK.shared.vehicleManager.currentVehicle.digitalKeyManager digitalKeyWithKeyCardType:XPKeyCardTypeSAFE];
415	        BOOL existCertOld = ![CTMediator isSDK2ndCar] && [XPBLEKeyManager.instance checkIsCertKeyCreatedWithVin:carInfo.vin uid:CTMediator.uid];
416	        BOOL existCertNew = [CTMediator isSDK2ndCar] && [XPVehicleSDK.shared.vehicleManager.currentVehicle.digitalKeyManager digitalKeyWithKeyCardType:XPKeyCardTypeCERT];
417	        if(existSafeOld || existSafeNew) {
418	            DLogTagInfo(kBLEKeyTag, @"存在安全钥匙，走删除安全钥匙流程（可能存在证书钥匙）");
419	            JRDeleteKeyViewController *deleteKeyViewController = [[JRDeleteKeyViewController alloc] init];
420	            deleteKeyViewController.vin = carInfo.vin;
421	            deleteKeyViewController.card = XPBLEKeyManager.instance.defaultCard;
422	            [self safePushViewController:deleteKeyViewController animated:YES];
423	        } else if(existCertOld || existCertNew) {
424	            DLogTagInfo(kBLEKeyTag, @"不存在安全钥匙，走删除证书钥匙流程");
425	            JRDeleteCertKeyViewController *deleteCertKeyViewController = [[JRDeleteCertKeyViewController alloc] init];
426	            deleteCertKeyViewController.vin = carInfo.vin;
427	            [self safePushViewController:deleteCertKeyViewController animated:YES];
428	        } else {
429	            DLogTagInfo(kBLEKeyTag, @"很奇怪钥匙不存在，走删除安全钥匙流程");
430	            JRDeleteKeyViewController *deleteKeyViewController = [[JRDeleteKeyViewController alloc] init];
431	            deleteKeyViewController.vin = carInfo.vin;
432	            deleteKeyViewController.card = card;
433	            [self safePushViewController:deleteKeyViewController animated:YES];
434	        }
435	    } else {
436	        DLogTagInfo(kBLEKeyTag, @"是新车型，跳到自研钥匙删除流程");
437	        if (![CTMediator isMona]) {
438	            JRDeleteCertKeyViewController *deleteCertKeyViewController = [[JRDeleteCertKeyViewController alloc] init];
439	            deleteCertKeyViewController.vin = carInfo.vin;
440	            [self safePushViewController:deleteCertKeyViewController animated:YES];
441	        } else {
442	            XPDeleteMonaKeyViewController *deleteMonaKeyViewController = [[XPDeleteMonaKeyViewController alloc] init];
443	            deleteMonaKeyViewController.vin = carInfo.vin;
444	            [self safePushViewController:deleteMonaKeyViewController animated:YES];
445	        }
446	    }
447	}
