743	        if(!self.bleLoginScreen){
744	            @weakify(self)
745	            [self showLoginAgreementPopViewWithConfirmBlock:^{
746	                @strongify(self)
747	                if (XPVehicleSDK.currentAbilityConfig.bleKeyVersion == BleKeyProtocolVesionV3) {
748	                    [self syncCdcuLoginSwitch:1];
