755	                }
756	            }];
757	        }else{
758	            if (XPVehicleSDK.currentAbilityConfig.bleKeyVersion == BleKeyProtocolVesionV3) {
759	                [self syncCdcuLoginSwitch:0];
760	               } else {
761	                   //关闭
762	                   self.bleLoginScreen = NO;
763	                   [self cellItemWithType:XPKeySettingCellTypeBleLoginScreen].switchSelected = self.bleLoginScreen;
764	                   [self.tableView reloadData];
765	                   
766	                   [XPCarStatisticsManager.sharedInstance addEvent:[XPCarStatisticsEvent eventWithPageId:XP_DIGITAL_KEY_MANAGER_MODULE buttonId:XP_DIGITAL_KEY_MANAGER_LOGIN_BIG_SCREEN data:@{@"operation": @(0)}]];
767	               }
768	        }
769	    }else if(cell.item.type == XPKeySettingCellTypeBleAutoUnlock){
770	        //靠近自动解锁
771	        if(!self.bleAutoUnlock){
772	            @weakify(self)
773	            [XPCarStatisticsManager.sharedInstance addEvent:[XPCarStatisticsEvent eventWithPageId:XP_DIGITAL_KEY_MANAGER_MODULE buttonId:XP_DIGITAL_KEY_MANAGER_AUTO_UNLOCK data:@{@"operation": @(1)}]];
774	            
775	            //打开，先检查白名单
776	            DLogTagInfo(@"pollingWhiteTag", @"是否在白名单:%d",[PollingEffectDataManager.sharedManager getPollingWhitelistFromMMKV]);
777	            if(CTMediator.isPollingFirst && !PollingEffectDataManager.sharedManager.getPollingWhitelistFromMMKV){
778	                [QMUIAlertController showAlertWithTitle:@"自动解闭锁设置"
779	                                                message:@"为保证使用体验，正在进行机型适配，请点击查看已适配机型"
780	                                       leftButtionTitle:@"好的"
781	                                         leftButtonType:QMUIAlertActionStyleCancel
782	                                             leftAction:nil
783	                                       rightButtonTitle:@"查看机型"
784	                                        rightButtonType:QMUIAlertActionStyleDefault
785	                                            rightAction:^(__kindof QMUIAlertController * _Nonnull alertVC, QMUIAlertAction * _Nonnull action) {
786	                    @strongify(self);
787	                    [self showPollingDetails:YES];
788	                }];
789	                return;
790	            }
791	            
792	            BOOL showPermissionPopup = ![MMKV.defaultMMKV getBoolForKey:kPermissionPopup];
793	            XPPrivacyPermissionAgreeBlock openPollingBlock = ^{
794	                @strongify(self)
795	                if([XPMultiBleManager checkIfPermissionGranted]){
796	                    self.bleAutoLockSound = NO;
797	                    [XPMultiBleManager.sharedManager switchPollingUnlock:YES];
798	                    [self updateSettingData];
799	                    [XPToast showMessage:@"开启成功"];
800	                    if ([XPCSelfConfigVCHandler needSelfConfigEntranceClass] && (XPMultiBleManager.sharedManager.pollingRunMode == PollingRunModeNone)) {
801	                        [XPSelfConfigPollingViewController enterSelfConfigWithAnimated:YES currentVC:self delegate:nil];
802	                        
803	                    }
804	                }else{
805	                    self.trySwitchAutoUnlock = YES;
806	                    [self showPermissionView];
807	                }
808	            };
809	            if(showPermissionPopup){
810	                [MMKV.defaultMMKV setBool:YES forKey:kPermissionPopup];
811	                [self showPopupViewWithAgreeBlock:openPollingBlock];
812	            }else{
813	                openPollingBlock();
814	            }
815	        }else{
816	            //关闭
817	            [XPCarStatisticsManager.sharedInstance addEvent:[XPCarStatisticsEvent eventWithPageId:XP_DIGITAL_KEY_MANAGER_MODULE buttonId:XP_DIGITAL_KEY_MANAGER_AUTO_UNLOCK data:@{@"operation": @(0)}]];
