819	            self.bleAutoLockSound = NO;
820	            [XPMultiBleManager.sharedManager switchPollingUnlock:NO];
821	            [self updateSettingData];
822	        }
823	    }else if(cell.item.type == XPKeySettingCellTypeBleAutoLock){
824	        //离开自动闭锁
825	        if(!self.bleAutoLock){
826	            @weakify(self);
827	            [XPCarStatisticsManager.sharedInstance addEvent:[XPCarStatisticsEvent eventWithPageId:XP_DIGITAL_KEY_MANAGER_MODULE buttonId:XP_DIGITAL_KEY_MANAGER_AUTO_LOCK data:@{@"operation": @(1)}]];
