831	                                     leftButtonType:QMUIAlertActionStyleCancel
832	                                         leftAction:nil
833	                                   rightButtonTitle:@"确认开启"
834	                                    rightButtonType:QMUIAlertActionStyleDefault
835	                                        rightAction:^(__kindof QMUIAlertController * _Nonnull alertVC, QMUIAlertAction * _Nonnull action) {
